     1→/**
     2→ * Mens HRT Enhanced PDP 1
     3→ * Page-specific styles for page-mens-hrt-enhanced-pdp.php
     4→ *
     5→ * Desktop-first: base styles target desktop (1440px).
     6→ * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
     7→ * Mobile-only refinements via $small-screen-only (max-width: 600px).
     8→ */
     9→@use '../variables/colors' as colors;
    10→@use '../variables/fonts' as fonts;
    11→@use '../variables/layout' as layout;
    12→
    13→.mens-hrt-enhanced-pdp-1 {
    14→
    15→	> *:not(.linkbar, .navbar, .site-footer) > .container {
    16→		max-width: 1440px;
    17→		margin: 0 auto;
    18→	}
    19→	.extended-center-border-above,
    20→	.extended-center-border-below {
    21→		@media #{layout.$medium-screen-and-smaller} {
    22→			&::before,
    23→			&::after {
    24→				display: none !important;
    25→			}
    26→		}
    27→	}
    28→
    29→	/*
    30→	* =============================
    31→	* Hero
    32→	* =============================
    33→	*/
    34→	.boost-your-testosterone.hero {
    35→		background-color: colors.$color-white;
    36→		padding: fonts.rem(40px) fonts.rem(64px);
    37→		@media #{layout.$medium-screen-and-smaller} {
    38→			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
    39→			flex-direction: column;
    40→			gap: fonts.rem(24px);
    41→		}
    42→		@media #{layout.$small-screen-only} {
    43→			padding-inline: fonts.rem(16px);
    44→		}
    45→
    46→		.container.grid {
    47→			gap: fonts.rem(64px);
    48→			grid-template-columns: 600px 1fr;
    49→			@media #{layout.$medium-screen-and-smaller} {
    50→				grid-template-columns: 1fr;
    51→				gap: fonts.rem(24px);
    52→			}
    53→		}
    54→
    55→		.container {
    56→			@media #{layout.$medium-screen-and-smaller} {
    57→				display: flex;
    58→				flex-direction: column;
    59→				gap: fonts.rem(24px);
    60→			}
    61→		}
    62→
    63→		// Left column — image
    64→		.media-wrapper {
    65→			padding: 0;
    66→			display: flex;
    67→			align-items: center;
    68→			background-color: colors.$color-white;
    69→			@media #{layout.$medium-screen-and-smaller} {
    70→				order: 1;
    71→			}
    72→
    73→			.media-block {
    74→				width: 600px;
    75→				aspect-ratio: 1 / 1;
    76→				@media #{layout.$medium-screen-and-smaller} {
    77→					width: 100%;
    78→					max-width: fonts.rem(600px);
    79→					height: auto;
    80→					margin-left: auto;
    81→					margin-right: auto;
    82→				}
    83→
    84→				video {
    85→					width: 100%;
    86→					height: 100%;
    87→					object-fit: cover;
    88→				}
    89→			}
    90→		}
    91→
    92→		// Right column — content
    93→		.content-wrapper {
    94→			padding: 0;
    95→			display: flex;
    96→			flex-direction: column;
    97→			justify-content: center;
    98→			gap: fonts.rem(40px);
    99→			@media #{layout.$medium-screen-and-smaller} {
   100→				order: 2;
   101→				gap: fonts.rem(24px);
   102→			}
   103→
   104→			// Title
   105→			.title-block h2 {
   106→				font-family: fonts.$STIX-Two-Text;
   107→				font-weight: 400;
   108→				font-size: fonts.rem(54px);
   109→				line-height: 1;
   110→				letter-spacing: -1.08px;
   111→				color: colors.$color-black;
   112→				max-width: 576px;
   113→				@media #{layout.$medium-screen-and-smaller} {
   114→					font-size: fonts.rem(36px);
   115→					letter-spacing: -0.72px;
   116→					max-width: none;
   117→				}
   118→			}
   119→
   120→			// List items
   121→			.content-block {
   122→				ul {
   123→					list-style: none;
   124→					margin: 0;
   125→					padding: 0;
   126→					display: flex;
   127→					flex-direction: column;
   128→					gap: fonts.rem(16px);
   129→					@media #{layout.$medium-screen-and-smaller} {
   130→						gap: fonts.rem(12px);
   131→					}
   132→				}
   133→
   134→				li {
   135→					border-left: 2px solid rgba(96, 91, 82, 0.2);
   136→					padding-left: fonts.rem(12px);
   137→					font-family: fonts.$DM-Sans;
   138→					font-weight: 500;
   139→					font-size: fonts.rem(22px);
   140→					line-height: 1.1;
   141→					letter-spacing: -0.44px;
   142→					color: colors.$color-black;
   143→					@media #{layout.$medium-screen-and-smaller} {
   144→						font-size: fonts.rem(18px);
   145→						letter-spacing: -0.36px;
   146→						padding-left: fonts.rem(8px);
   147→					}
   148→				}
   149→			}
   150→
   151→			// CTA block
   152→			.cta-block {
   153→				display: flex;
   154→				flex-direction: column;
   155→				gap: fonts.rem(8px);
   156→				width: 100%;
   157→
   158→				.cta-wrapper {
   159→					width: 100%;
   160→				}
   161→
   162→				a {
   163→					width: 100%;
   164→					height: 48px;
   165→					border-radius: 2px;
   166→					padding: 0 fonts.rem(48px);
   167→					box-sizing: border-box;
   168→				}
   169→			}
   170→
   171→			// Badges — pull up to 8px below CTA (40px gap - 32px = 8px)
   172→			.badges-wrapper {
   173→				margin-top: fonts.rem(-32px);
   174→				display: flex;
   175→				flex-wrap: wrap;
   176→				align-items: center;
   177→				justify-content: center;
   178→				gap: fonts.rem(10px);
   179→				// Adjust for 24px gap (24px - 16px = 8px)
   180→				@media #{layout.$medium-screen-and-smaller} {
   181→					margin-top: fonts.rem(-16px);
   182→				}
   183→
   184→				.badge {
   185→					display: flex;
   186→					align-items: center;
   187→					height: 20px;
   188→
   189→					img {
   190→						width: auto;
   191→						height: 24px;
   192→					}
   193→
   194→					span {
   195→						font-family: fonts.$DM-Sans;
   196→						font-weight: 400;
   197→						font-size: fonts.rem(14px);
   198→						line-height: 1.4;
   199→						letter-spacing: -0.28px;
   200→						color: colors.$color-gray;
   201→						text-align: center;
   202→					}
   203→				}
   204→			}
   205→		}
   206→	}
   207→
   208→	/*
   209→	* =============================
   210→	* Marquee / Trustpilot Ratings
   211→	* =============================
   212→	*/
   213→	.marquee.trustpilot-ratings {
   214→		background-color: colors.$color-white;
   215→
   216→		.container {
   217→			display: flex;
   218→			align-items: center;
   219→			gap: fonts.rem(16px);
   220→			padding: fonts.rem(16px);
   221→			@media #{layout.$medium-screen-and-smaller} {
   222→				flex-direction: column;
   223→				padding: fonts.rem(16px) 0;
   224→			}
   225→		}
   226→
   227→		.trustpilot-wrapper {
   228→			flex-shrink: 0;
   229→			@media only screen and (max-width: 445px) {
   230→				min-width: unset;
   231→			}
   232→		}
   233→
   234→		.trustpilot-static {
   235→			display: flex;
   236→			align-items: center;
   237→			gap: fonts.rem(8px);
   238→			text-decoration: none;
   239→			color: #191919;
   240→			white-space: nowrap;
   241→
   242→			.tp-text {
   243→				font-weight: 700;
   244→				font-size: fonts.rem(12px);
   245→			}
   246→
   247→			.tp-stars {
   248→				height: 14px;
   249→			}
   250→
   251→			.tp-count {
   252→				font-size: fonts.rem(12px);
   253→			}
   254→
   255→			.tp-brandmark {
   256→				width: auto;
   257→				height: 16px;
   258→			}
   259→
   260→			@media only screen and (max-width: 445px) {
   261→				flex-wrap: wrap;
   262→				justify-content: center;
   263→				gap: fonts.rem(4px) fonts.rem(8px);
   264→			}
   265→		}
   266→
   267→		.reviews-wrapper {
   268→			flex: 1 0 0;
   269→			overflow: hidden;
   270→			position: relative;
   271→			@media #{layout.$medium-screen-and-smaller} {
   272→				flex: 0 0 auto;
   273→				width: 100%;
   274→			}
   275→
   276→			// Fade edges
   277→			&::before,
   278→			&::after {
   279→				content: '';
   280→				position: absolute;
   281→				top: 0;
   282→				bottom: 0;
   283→				width: 78px;
   284→				z-index: 1;
   285→				pointer-events: none;
   286→			}
   287→
   288→			&::before {
   289→				left: 0;
   290→				background: linear-gradient(to right, colors.$color-white, transparent);
   291→			}
   292→
   293→			&::after {
   294→				right: 0;
   295→				background: linear-gradient(to left, colors.$color-white, transparent);
   296→			}
   297→		}
   298→
   299→		.reviews-marquee {
   300→			display: flex;
   301→			width: max-content;
   302→			will-change: transform;
   303→			animation: marquee-scroll calc(var(--review-count, 4) * 3s) linear infinite;
   304→		}
   305→
   306→		.reviews-set {
   307→			display: flex;
   308→			flex-shrink: 0;
   309→		}
   310→
   311→		.review-item {
   312→			display: flex;
   313→			align-items: center;
   314→			gap: fonts.rem(8px);
   315→			flex-shrink: 0;
   316→			white-space: nowrap;
   317→			margin-right: fonts.rem(16px);
   318→
   319→			.quote-content {
   320→				font-family: fonts.$DM-Sans;
   321→				font-weight: 400;
   322→				font-size: fonts.rem(16px);
   323→				line-height: 1.4;
   324→				letter-spacing: -0.16px;
   325→				color: colors.$color-black;
   326→			}
   327→
   328→			.reviewer-details {
   329→				font-family: fonts.$DM-Sans;
   330→				font-weight: 400;
   331→				font-size: fonts.rem(16px);
   332→				line-height: 1.4;
   333→				letter-spacing: -0.16px;
   334→				color: colors.$color-gray;
   335→			}
   336→		}
   337→	}
   338→
   339→	/*
   340→	* =============================
   341→	* How It Works / Social Videos
   342→	* =============================
   343→	*/
   344→	.how-it-works.social-videos {
   345→		padding: fonts.rem(64px) 0;
   346→		position: relative;
   347→		@media #{layout.$medium-screen-and-smaller} {
   348→			padding: fonts.rem(40px) 0;
   349→		}
   350→
   351→		&.extended-center-border-below::after {
   352→			left: 50%;
   353→		}
   354→
   355→		&::before {
   356→			@media #{layout.$medium-screen-and-smaller} {
   357→				display: none;
   358→			}
   359→		}
   360→
   361→		.container {
   362→			position: relative;
   363→			z-index: 1;
   364→			background-color: colors.$color-white;
   365→			border-radius: 20px;
   366→			padding: fonts.rem(32px) 0;
   367→			display: flex;
   368→			flex-direction: column;
   369→			gap: fonts.rem(32px);
   370→			@media #{layout.$medium-screen-and-smaller} {
   371→				padding: 0;
   372→				border-radius: 0;
   373→				background-color: transparent;
   374→			}
   375→		}
   376→
   377→		// Title block
   378→		.title-wrapper {
   379→			display: flex;
   380→			flex-direction: column;
   381→			gap: fonts.rem(16px);
   382→			align-items: center;
   383→			text-align: center;
   384→			@media #{layout.$medium-screen-and-smaller} {
   385→				gap: fonts.rem(8px);
   386→			}
   387→
   388→			.title {
   389→				font-family: fonts.$STIX-Two-Text;
   390→				font-weight: 400;
   391→				font-size: fonts.rem(54px);
   392→				line-height: 1;
   393→				letter-spacing: -1.08px;
   394→				color: colors.$color-black;
   395→				@media #{layout.$medium-screen-and-smaller} {
   396→					font-size: fonts.rem(36px);
   397→					letter-spacing: -0.72px;
   398→				}
   399→			}
   400→
   401→			.subtitle {
   402→				font-family: fonts.$DM-Sans;
   403→				font-weight: 500;
   404→				font-size: fonts.rem(22px);
   405→				line-height: 1;
   406→				letter-spacing: -0.44px;
   407→				color: colors.$color-black;
   408→				@media #{layout.$medium-screen-and-smaller} {
   409→					font-size: fonts.rem(18px);
   410→					letter-spacing: -0.36px;
   411→				}
   412→			}
   413→		}
   414→
   415→		// Video cards row
   416→		.carousel-wrapper {
   417→			padding: 0;
   418→			display: flex;
   419→			gap: fonts.rem(24px);
   420→			align-items: center;
   421→			justify-content: center;
   422→			@media #{layout.$medium-screen-and-smaller} {
   423→				gap: fonts.rem(8px);
   424→				justify-content: flex-start;
   425→				overflow-x: auto;
   426→				-webkit-overflow-scrolling: touch;
   427→				scrollbar-width: none;
   428→
   429→				&::-webkit-scrollbar {
   430→					display: none;
   431→				}
   432→			}
   433→			.review-video-item:first-child {
   434→				margin-left: fonts.rem(32px);
   435→				@media #{layout.$small-screen-only} {
   436→					margin-left: fonts.rem(16px);
   437→				}
   438→			}
   439→			.review-video-item:last-child {
   440→				margin-right: fonts.rem(32px);
   441→				@media #{layout.$small-screen-only} {
   442→					margin-right: fonts.rem(16px);
   443→				}
   444→			}
   445→		}
   446→
   447→		.review-video-item {
   448→			width: 270px;
   449→			height: 480px;
   450→			border-radius: 20px;
   451→			overflow: hidden;
   452→			position: relative;
   453→			background-color: colors.$color-gray-light;
   454→			flex-shrink: 0;
   455→			cursor: pointer;
   456→
   457→			.thumbnail-wrapper {
   458→				position: absolute;
   459→				inset: 0;
   460→				z-index: 1;
   461→				transition: opacity 0.3s ease;
   462→
   463→				img {
   464→					width: 100%;
   465→					height: 100%;
   466→					object-fit: cover;
   467→				}
   468→			}
   469→
   470→			.video-wrapper {
   471→				position: absolute;
   472→				inset: 0;
   473→
   474→				video {
   475→					width: 100%;
   476→					height: 100%;
   477→					object-fit: cover;
   478→				}
   479→			}
   480→
   481→		.play-button {
   482→			position: absolute;
   483→			top: 50%;
   484→			left: 50%;
   485→			transform: translate(-50%, -50%);
   486→			z-index: 2;
   487→			width: 72px;
   488→			height: 72px;
   489→			border-radius: 50%;
   490→			border: none;
   491→			background: rgba(255, 255, 255, 0.75);
   492→			color: rgba(0, 0, 0, 0.75);
   493→			cursor: pointer;
   494→			display: flex;
   495→			align-items: center;
   496→			justify-content: center;
   497→			transition: opacity 0.3s ease, background 0.2s ease;
   498→			pointer-events: none;
   499→
   500→			svg {
   501→				margin-left: 3px;
   502→				fill: rgba(0, 0, 0, 0.4);
   503→			}
   504→
   505→			&:hover {
   506→				background: rgba(255, 255, 255, 0.9);
   507→			}
   508→		}
   509→
   510→		&.playing .play-button {
   511→			opacity: 0;
   512→		}
   513→
   514→		.mute-toggle {
   515→			position: absolute;
   516→			bottom: 12px;
   517→			right: 12px;
   518→			z-index: 3;
   519→			width: 36px;
   520→			height: 36px;
   521→			border-radius: 50%;
   522→			border: none;
   523→			background: rgba(0, 0, 0, 0.55);
   524→			color: colors.$color-white;
   525→			cursor: pointer;
   526→			display: flex;
   527→			align-items: center;
   528→			justify-content: center;
   529→			opacity: 0;
   530→			transition: opacity 0.3s ease, background 0.2s ease;
   531→			padding: 0;
   532→
   533→			&:hover {
   534→				background: rgba(0, 0, 0, 0.75);
   535→			}
   536→
   537→			.icon-unmuted {
   538→				display: none;
   539→			}
   540→		}
   541→
   542→		&.playing .thumbnail-wrapper {
   543→			opacity: 0;
   544→		}
   545→
   546→		&.playing .mute-toggle {
   547→			opacity: 1;
   548→		}
   549→
   550→		&.unmuted .mute-toggle {
   551→			.icon-muted {
   552→				display: none;
   553→			}
   554→			.icon-unmuted {
   555→				display: block;
   556→			}
   557→		}
   558→	}
   559→	}
   560→
   561→	/*
   562→	* =============================
   563→	* Benefits Timeline
   564→	* =============================
   565→	*/
   566→	.benefits-timeline {
   567→		background-color: colors.$color-white;
   568→		padding: fonts.rem(32px) 0;
   569→		position: relative;
   570→		@media #{layout.$medium-screen-and-smaller} {
   571→			padding: fonts.rem(40px) 0;
   572→		}
   573→
   574→		.container {
   575→			position: relative;
   576→			z-index: 1;
   577→			background-color: colors.$color-white;
   578→			display: flex;
   579→			flex-direction: column;
   580→			gap: fonts.rem(32px);
   581→			padding: fonts.rem(32px) 0 fonts.rem(80px);
   582→			@media #{layout.$medium-screen-and-smaller} {
   583→				padding: 0;
   584→				gap: fonts.rem(40px);
   585→				padding: 0;
   586→				background-color: transparent;
   587→			}
   588→		}
   589→
   590→		// Title
   591→		.title-block {
   592→			text-align: center;
   593→
   594→			.title {
   595→				font-family: fonts.$STIX-Two-Text;
   596→				font-weight: 400;
   597→				font-size: fonts.rem(54px);
   598→				line-height: 1;
   599→				letter-spacing: -1.08px;
   600→				color: colors.$color-black;
   601→				@media #{layout.$medium-screen-and-smaller} {
   602→					font-size: fonts.rem(36px);
   603→					letter-spacing: -0.72px;
   604→				}
   605→			}
   606→		}
   607→
   608→		// Cards row
   609→		.timeline-wrapper {
   610→			padding: 0;
   611→		}
   612→
   613→		.benefits-timeline-carousel {
   614→			display: flex;
   615→			justify-content: center;
   616→			align-items: stretch; // all cards same height so dividers align
   617→			width: 100%;
   618→			@media #{layout.$medium-screen-and-smaller} {
   619→				justify-content: flex-start;
   620→				overflow-x: auto;
   621→				-webkit-overflow-scrolling: touch;
   622→				scrollbar-width: none;
   623→
   624→				&::-webkit-scrollbar {
   625→					display: none;
   626→				}
   627→			}
   628→		}
   629→
   630→		// Individual card
   631→		// Image has fixed height so the divider line stays at a constant
   632→		// vertical position across all cards during expand/collapse.
   633→		.timeline-card {
   634→			display: flex;
   635→			flex-direction: column;
   636→			gap: fonts.rem(8px);
   637→			width: 250px;
   638→			flex-shrink: 0;
   639→			opacity: 0.8;
   640→			cursor: pointer;
   641→			transition: width 0.4s ease, opacity 0.4s ease;
   642→			@media #{layout.$medium-screen-and-smaller} {
   643→				max-width: 325px;
   644→				width: 100vw;
   645→				opacity: 1;
   646→				cursor: default;
   647→				transition: none;
   648→			}
   649→			&:first-child {
   650→				margin-left: fonts.rem(32px);
   651→				@media #{layout.$small-screen-only} {
   652→					margin-left: fonts.rem(16px);
   653→				}
   654→				@media only screen and (max-width: 315px) {
   655→					margin-left: fonts.rem(8px);
   656→				}
   657→			}
