    14→/**
    15→ * How It Works — click-to-play video cards
    16→ * - Thumbnail shows by default as placeholder
    17→ * - On click: lazy-load video src, play, hide thumbnail
    18→ * - Clicking a playing video pauses it
    19→ * - Only one video plays at a time
    20→ */
    21→function initSocialVideos() {
    22→	const items = document.querySelectorAll('.how-it-works.social-videos .review-video-item');
    23→	const loadedMap = new WeakMap();
    24→
    25→	function loadAndPlay(item) {
    26→		const video = item.querySelector('video');
    27→		if (!video) return;
    28→
    29→		items.forEach((other) => {
    30→			if (other !== item) stopVideo(other);
    31→		});
    32→
    33→		if (!loadedMap.get(video)) {
    34→			const lazySrc = video.getAttribute('data-src');
    35→			if (!lazySrc) return;
    36→			video.src = lazySrc;
    37→			video.load();
    38→			loadedMap.set(video, true);
    39→		}
    40→
    41→		video.play().then(() => {
    42→			item.classList.add('playing');
    43→		}).catch(() => {});
    44→	}
    45→
    46→	function stopVideo(item) {
    47→		const video = item.querySelector('video');
    48→		if (!video) return;
    49→		video.pause();
    50→		item.classList.remove('playing');
    51→	}
    52→
    53→	items.forEach((item) => {
    54→		const video = item.querySelector('video');
    55→		const muteBtn = item.querySelector('.mute-toggle');
    56→		if (!video) return;
    57→
    58→		item.addEventListener('click', () => {
    59→			if (item.classList.contains('playing')) {
    60→				stopVideo(item);
    61→			} else {
    62→				loadAndPlay(item);
    63→			}
    64→		});
    65→
    66→		if (muteBtn) {
    67→			muteBtn.addEventListener('click', (e) => {
    68→				e.stopPropagation();
    69→				const shouldUnmute = video.muted;
    70→
    71→				if (shouldUnmute) {
    72→					items.forEach((other) => {
    73→						const otherVideo = other.querySelector('video');
    74→						if (otherVideo && otherVideo !== video) {
    75→							otherVideo.muted = true;
    76→							other.classList.remove('unmuted');
    77→							const otherBtn = other.querySelector('.mute-toggle');
    78→							if (otherBtn) otherBtn.setAttribute('aria-label', 'Unmute video');
    79→						}
    80→					});
    81→				}
    82→
    83→				video.muted = !shouldUnmute;
    84→				item.classList.toggle('unmuted', shouldUnmute);
    85→				muteBtn.setAttribute('aria-label', shouldUnmute ? 'Mute video' : 'Unmute video');
    86→			});
    87→		}
    88→	});
    89→
    90→	// Autoplay first video when the section scrolls into view
    91→	const firstItem = items[0];
    92→	if (firstItem) {
    93→		const observer = new IntersectionObserver((entries) => {
    94→			entries.forEach((entry) => {
    95→				if (entry.isIntersecting) {
    96→					loadAndPlay(firstItem);
    97→					observer.disconnect();
    98→				}
    99→			});
   100→		}, { threshold: 0.3 });
   101→
   102→		observer.observe(firstItem);
   103→	}
   104→}
